import isPlainObject from './isPlainObject';
import isPrimitive from './isPrimitive';

const isEmptyObjectWithCustomPrototype = (object: object, keys: string[]) =>
  keys.length === 0 && !Array.isArray(object) && !isPlainObject(object);

type VisitedPairs = WeakMap<object, WeakSet<object>>;

export default function deepEqual(
  object1: any,
  object2: any,
  visited: VisitedPairs = new WeakMap(),
) {
  if (object1 === object2) {
    return true;
  }

  if (isPrimitive(object1) || isPrimitive(object2)) {
    return Object.is(object1, object2);
  }

  if (isDateObject(object1) && isDateObject(object2)) {
    return Object.is(object1.getTime(), object2.getTime());
  }

  const keys1 = Object.keys(object1);
  const keys2 = Object.keys(object2);

  if (keys1.length !== keys2.length) {
    return false;
  }

  if (
    isEmptyObjectWithCustomPrototype(object1, keys1) ||
    isEmptyObjectWithCustomPrototype(object2, keys2)
  ) {
    return Object.is(object1, object2);
  }

  // Only an object pair that is active on the current recursion path indicates a cycle.
  let object1Pairs = visited.get(object1);
  if (object1Pairs?.has(object2)) {
    return true;
  }

  if (!object1Pairs) {
    object1Pairs = new WeakSet();
    visited.set(object1, object1Pairs);
  }
  object1Pairs.add(object2);

  try {
    for (const key of keys1) {
      const val1 = object1[key];

      if (!(key in object2)) {
        return false;
      }

      if (key !== 'ref') {
        const val2 = object2[key];

        if (
          (isDateObject(val1) && isDateObject(val2)) ||
          ((isObject(val1) || Array.isArray(val1)) &&
            (isObject(val2) || Array.isArray(val2)))
            ? !deepEqual(val1, val2, visited)
            : !Object.is(val1, val2)
        ) {
          return false;
        }
      }
    }

    return true;
  } finally {
    object1Pairs.delete(object2);
  }
}

